<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#C792EA;">var</span><span style="--shiki-light:#24292E;--shiki-dark:#BABED8;"> $b </span><span style="--shiki-light:#D73A49;--shiki-dark:#89DDFF;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#F78C6C;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#89DDFF;">;</span><span style="--shiki-light:#6A737D;--shiki-light-font-style:inherit;--shiki-dark:#464B5D;--shiki-dark-font-style:italic;"> // 申明了变量$b，同时给$b赋值，此时$b的值为1</span></span>
